import{_ as d,o as r,c as a,a2 as h}from"./chunks/framework.Bkqnpl2X.js";const c=JSON.parse('{"title":"附录D 关键公式速查卡片","description":"","frontmatter":{},"headers":[],"relativePath":"guide/appendix/appendix-d.md","filePath":"guide/appendix/appendix-d.md","lastUpdated":1780443280000}'),e={name:"guide/appendix/appendix-d.md"};function o(n,t,l,i,s,p){return r(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="附录d-关键公式速查卡片" tabindex="-1">附录D 关键公式速查卡片 <a class="header-anchor" href="#附录d-关键公式速查卡片" aria-label="Permalink to &quot;附录D 关键公式速查卡片&quot;">​</a></h1><p><strong>版本</strong>： V5.0 | <strong>所属</strong>：Avis航空航天阀门研发设计手册 | <strong>新增于</strong>：V5.0</p><hr><h2 id="d-1-流体力学与热力学" tabindex="-1">D.1 流体力学与热力学 <a class="header-anchor" href="#d-1-流体力学与热力学" aria-label="Permalink to &quot;D.1 流体力学与热力学&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>表达式</th><th>物理意义</th><th>典型参数范围</th><th>相关章</th></tr></thead><tbody><tr><td>Bernoulli</td><td>p + ½ρv² + ρgz = const</td><td>流线能量守恒（无粘定常不可压缩流）</td><td>LOX阀: ρ≈1140 kg/m³</td><td>Ch2</td></tr><tr><td>C_v流量系数</td><td>Q = C_v·√(Δp/SG)</td><td>阀门流量能力度量</td><td>全开阀C_v: 10-500（按口径）</td><td>Ch2</td></tr><tr><td>水锤（Joukowsky）</td><td>Δp = ρ·c·Δv</td><td>阀门关闭速度激发的压力波</td><td>LH₂: c≈1200 m/s→关闭1m/s→Δp≈0.84 MPa</td><td>Ch2</td></tr><tr><td>阻塞流判据</td><td>p₂/p₁ ≤ (2/(k+1))^(k/(k-1))</td><td>阀门下游压力低于临界比→质量流量不随p₂下降而增加→流量&quot;阻塞&quot;</td><td>空气 k=1.4→临界比 0.528; 氦 k=1.66→0.488</td><td>Ch2</td></tr><tr><td>理想气体</td><td>p = ρRT</td><td>气体状态方程</td><td>氦: R=2077 J/(kg·K)</td><td>Ch3</td></tr><tr><td>Eaton压缩气体定律</td><td>p₁V₁/T₁ = p₂V₂/T₂</td><td>气缸/气动阀门中压缩气体膨胀</td><td>—</td><td>Ch14</td></tr></tbody></table><hr><h2 id="d-2-结构力学" tabindex="-1">D.2 结构力学 <a class="header-anchor" href="#d-2-结构力学" aria-label="Permalink to &quot;D.2 结构力学&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>表达式</th><th>物理意义</th><th>典型参数范围</th><th>相关章</th></tr></thead><tbody><tr><td>Hoop应力（薄壁）</td><td>σ_h = p·D/(2t)</td><td>阀体周向应力</td><td>SSME阀: p≈45 MPa, D≈150mm, t≈8mm→σ_h≈422 MPa</td><td>Ch7</td></tr><tr><td>Lamé应力（厚壁筒）</td><td>σ_h = p·(1+(rₒ/r)²)/(K²-1)</td><td>周向应力分布（K=rₒ/rᵢ）</td><td>K=1.5→内壁σ_h≈1.8p</td><td>Ch7</td></tr><tr><td>Hertz接触应力</td><td>p_max = (3F/(2πa²))·√(1-(z/a)²)</td><td>球-平面接触（密封面Hertz应力）</td><td>Inconel球（φ5mm）vs 阀座, F=1kN→p_max≈3 GPa</td><td>Ch7</td></tr><tr><td>Euler屈曲</td><td>F_cr = π²EI/(KL)²</td><td>阀杆失稳临界力</td><td>阀杆φ8×100mm, K=1→F_cr≈ 40kN (304L)</td><td>Ch7</td></tr><tr><td>Archard磨损</td><td>V = k·F·s/H</td><td>磨损体积∝载荷·滑动距离·磨损系数k/硬度H</td><td>阀芯配合面: k≈10⁻⁵⁻10⁻⁴; H≈3-5 GPa</td><td>Ch26</td></tr><tr><td>Coffin-Manson (LCF)</td><td>ε_a = (σ_f&#39;/E)·(2N_f)^b + ε_f&#39;·(2N_f)^c</td><td>低周疲劳寿命（塑性+弹性应变分量）</td><td>Inconel 718: ε_f&#39;≈0.2-0.5, c≈-0.5至-0.7</td><td>Ch7, Ch26</td></tr></tbody></table><hr><h2 id="d-3-可靠性统计" tabindex="-1">D.3 可靠性统计 <a class="header-anchor" href="#d-3-可靠性统计" aria-label="Permalink to &quot;D.3 可靠性统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>表达式</th><th>物理意义</th><th>典型参数范围</th><th>相关章</th></tr></thead><tbody><tr><td>Weibull可靠度</td><td>R(t) = exp(-(t/η)^β)</td><td>在t时刻仍无故障的概率</td><td>β（形状参数）：阀门疲劳β≈1.5-3</td><td>Ch32, Ch55</td></tr><tr><td>Weibull B₁₀寿命</td><td>t₀.₁₀ = η·(-ln(0.9))^(1/β)</td><td>10%阀门群体已发生故障的时刻</td><td>用于设计验证目标的最低可靠寿命</td><td>Ch32</td></tr><tr><td>二项式无失效</td><td>R = α^(1/n)</td><td>n件试验全部通过→在α置信度下的可靠度</td><td>n=1→无统计意义; n≥3→可实现α=0.5的R&gt;0.8</td><td>Ch35, Ch55</td></tr><tr><td>Arrhenius加速因子</td><td>AF = exp[(E_a/k)·(1/T_use - 1/T_accel)]</td><td>温度加速寿命试验的加速倍数</td><td>E_a (活化能) Inconel蠕变~300 kJ/mol; k=8.617×10⁻⁵ eV/K</td><td>Ch55</td></tr><tr><td>逆幂律加速因子</td><td>AF = (S_accel/S_use)^n</td><td>应力加速的寿命增益</td><td>n（指数）金属疲劳≈3-5</td><td>Ch55</td></tr><tr><td>Bayes后验</td><td>p(λ</td><td>data) ∝ p(data</td><td>λ)·p(λ)</td><td>结合飞行数据更新故障率估计</td></tr></tbody></table><hr><h2 id="d-4-电磁与机电" tabindex="-1">D.4 电磁与机电 <a class="header-anchor" href="#d-4-电磁与机电" aria-label="Permalink to &quot;D.4 电磁与机电&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>表达式</th><th>物理意义</th><th>典型参数范围</th><th>相关章</th></tr></thead><tbody><tr><td>电磁力（螺线管）</td><td>F = (μ₀·N²·A·I²)/(2g²)</td><td>电磁铁静态力（忽略铁芯饱和）</td><td>N=1000匝,A=2cm²,I=2A,g=0.5mm→F≈100N</td><td>Ch13</td></tr><tr><td>压电本构 (d₃₃模式)</td><td>S₃ = s₃₃^E·T₃ + d₃₃·E₃</td><td>压电堆叠应变=弹性+压电分量</td><td>d₃₃≈400-700 pC/N(PZT-5H)</td><td>Ch53</td></tr><tr><td>压电行程</td><td>ΔL = n·d₃₃·V</td><td>n层堆叠, 电压V下的总行程</td><td>100层, 150V, d₃₃=600 pC/N→ΔL≈9 μm</td><td>Ch53</td></tr><tr><td>LVDT灵敏度</td><td>V_out = k·x·V_exc·sin(ωt)</td><td>铁芯位移x→次级差动电压</td><td>灵敏度: 10-100 mV/(mm·V_exc)</td><td>Ch54</td></tr></tbody></table><hr><h2 id="d-5-cfd核心" tabindex="-1">D.5 CFD核心 <a class="header-anchor" href="#d-5-cfd核心" aria-label="Permalink to &quot;D.5 CFD核心&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>表达式</th><th>物理意义</th><th>相关章</th></tr></thead><tbody><tr><td>Navier-Stokes</td><td>ρ(∂u/∂t + u·∇u) = -∇p + μ∇²u + ρg</td><td>不可压缩粘性流体动量方程</td><td>Ch11</td></tr><tr><td>湍流k-ε模型</td><td>ν_t = C_μ·k²/ε</td><td>涡粘系数（湍流粘度的k-ε模型）</td><td>Ch11</td></tr><tr><td>CFL条件</td><td>CFL = u·Δt/Δx ≤ 1</td><td>显式求解器时间步长稳定性判据</td><td>Ch11</td></tr><tr><td>y⁺ (壁面距离)</td><td>y⁺ = y·u_τ/ν</td><td>首层网格壁面距离与摩擦速度的无量纲量</td><td>Ch11</td></tr></tbody></table><hr><h2 id="d-6-密封与泄漏" tabindex="-1">D.6 密封与泄漏 <a class="header-anchor" href="#d-6-密封与泄漏" aria-label="Permalink to &quot;D.6 密封与泄漏&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>表达式</th><th>物理意义</th><th>典型参数</th><th>相关章</th></tr></thead><tbody><tr><td>密封面接触应力最小准则</td><td>σ_c ≥ m·p</td><td>垫片系数法: 接触应力≥系数m×内压</td><td>金属O-ring: m≈5-7</td><td>Ch12</td></tr><tr><td>氦质谱泄漏率</td><td>Q_He = (Δp·V)/Δt</td><td>真空腔压力上升速率→泄漏率</td><td>航天阀门: Q_He≤1×10⁻⁵ sccs (验收)</td><td>Ch12, Ch54</td></tr><tr><td>分子流泄漏 (Kn&gt;1)</td><td>Q = (π·d⁴·Δp)/(128·η·L)</td><td>微孔道层流泄漏 (Poiseuille)</td><td>微通道 d&lt;10μm→分子流→更复杂</td><td>Ch12</td></tr></tbody></table><hr><h2 id="d-7-符号表" tabindex="-1">D.7 符号表 <a class="header-anchor" href="#d-7-符号表" aria-label="Permalink to &quot;D.7 符号表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>符号</th><th>含义</th><th>单位</th></tr></thead><tbody><tr><td>ρ</td><td>密度</td><td>kg/m³</td></tr><tr><td>p</td><td>压力</td><td>Pa (或 MPa)</td></tr><tr><td>v, u</td><td>速度</td><td>m/s</td></tr><tr><td>μ, η</td><td>动力粘度</td><td>Pa·s</td></tr><tr><td>ν</td><td>运动粘度 (ν=μ/ρ)；或Poisson比</td><td>m²/s, 无量纲</td></tr><tr><td>σ</td><td>应力</td><td>Pa (或 MPa)</td></tr><tr><td>ε</td><td>应变</td><td>无量纲</td></tr><tr><td>E</td><td>弹性模量</td><td>Pa (或 GPa)</td></tr><tr><td>k</td><td>导热系数, 或比热比c_p/c_v, 或磨损系数</td><td>W/(m·K), 无量纲, 无量纲</td></tr><tr><td>H</td><td>硬度</td><td>Pa (或 HV/GPa)</td></tr><tr><td>dₓₓ</td><td>压电系数</td><td>pC/N 或 pm/V</td></tr><tr><td>K</td><td>应力集中系数, 或 Lamé系数比率</td><td>无量纲</td></tr><tr><td>T</td><td>温度</td><td>K (低温) 或 °C</td></tr></tbody></table><hr><blockquote><p><strong>附录D编写说明</strong>：本附录作为工程师&quot;随身公式手册&quot;——在设计评审、快速计算或故障分析时无需翻阅完整章节即可找到核心公式。每个公式标注了参照的完整章节以便深入查阅。所有公式的符号定义与本书正文保持一致。 <em>（内容由AI生成，仅供参考）</em><em>（内容由AI生成，仅供参考）</em></p></blockquote>',25)])])}const _=d(e,[["render",o]]);export{c as __pageData,_ as default};
